734:   private static Optional<Root> computeSourceRoot(Metadata metadata) {
735:     if (metadata.isRepoRulePackage()) {
736:       return Optional.empty();
737:     }
738: 
739:     RootedPath buildFileRootedPath = metadata.buildFilename();
740:     Root buildFileRoot = buildFileRootedPath.getRoot();
741:     PathFragment pkgIdFragment = metadata.packageIdentifier().getSourceRoot();
742:     PathFragment pkgDirFragment = buildFileRootedPath.getRootRelativePath().getParentDirectory();
743: 
744:     Root sourceRoot;
745:     if (pkgIdFragment.equals(pkgDirFragment)) {
746:       // Fast path: BUILD file path and package name are the same, don't create an extra root.
747:       sourceRoot = buildFileRoot;
748:     } else {
749:       // TODO(bazel-team): Can this expr be simplified to just pkgDirFragment?
750:       PathFragment current = buildFileRootedPath.asPath().asFragment().getParentDirectory();
751:       for (int i = 0, len = pkgIdFragment.segmentCount(); i < len && current != null; i++) {
752:         current = current.getParentDirectory();
753:       }
754:       if (current == null || current.isEmpty()) {
755:         // This is never really expected to work. The below check should fail.
756:         sourceRoot = buildFileRoot;
757:       } else {
758:         // Note that current is an absolute path.
759:         sourceRoot = Root.fromPath(buildFileRoot.getRelative(current));
760:       }
761:     }
762: 
763:     Preconditions.checkArgument(
764:         sourceRoot.asPath() != null
765:             && sourceRoot.getRelative(pkgIdFragment).equals(metadata.getPackageDirectory()),
766:         "Invalid BUILD file name for package '%s': %s (in source %s with packageDirectory %s and"
767:             + " package identifier source root %s)",
768:         metadata.packageIdentifier(),
769:         metadata.buildFilename(),
770:         sourceRoot,
771:         metadata.getPackageDirectory(),
772:         metadata.packageIdentifier().getSourceRoot());
773: 
774:     return Optional.of(sourceRoot);
775:   }
